import Mathlib.Data.List

structure CupcakeDistribution where
  m : Nat
  n : Nat
  scores : List (List Nat)
  distribution : List (List Nat)

def CupcakeDistribution.valid (cd : CupcakeDistribution) : Prop :=
  ∀ (i : Fin cd.n), (cd.distribution.nth i).foldl (· + ·) 0 ≥ 1

def CupcakeDistribution.construct (m n : Nat) (scores : List (List Nat)) : CupcakeDistribution :=
{
  m := m,
  n := n,
  scores := scores,
  distribution := List.ofFn (λ i, List.nil)
}

def CupcakeDistribution.assign (cd : CupcakeDistribution) (cupcake : Nat) (person : Fin cd.n) : CupcakeDistribution :=
{
  m := cd.m,
  n := cd.n,
  scores := cd.scores,
  distribution := cd.distribution.set person (cd.distribution.nth person ++ [cupcake])
}

theorem CupcakeDistribution.exists_valid_distribution (m n : Nat) (scores : List (List Nat)) : ∃ (cd : CupcakeDistribution), CupcakeDistribution.valid cd :=
begin
  -- Construct an initial distribution
  let cd := CupcakeDistribution.construct m n scores;

  -- Assign cupcakes to people
  let cd := List.foldl (λ cd cupcake, let person := (cd.distribution.map (λ l, l.foldl (· + ·) 0)).argmax; cd.assign cupcake person) cd (List.range m);

  -- Show that the constructed distribution is valid
  use cd;
  intros i;
  apply List.foldl_ge_one_of_exists_ge_one;
  exists (cd.distribution.nth i);
  apply List.exists_of_mem;
  apply List.mem_of_nth;
  apply Fin.valid_lt;
  apply Nat.lt_of_le_of_lt;
  apply Nat.le_add_right;
  apply Nat.zero_le;
end
